INSERT INTO `tms_vi_page` VALUES
(8, 'DANH SÁCH ĐĂNG KÝ TIÊM CHỦNG NGÀY 28&#x002F;03&#x002F;2019', 'ds28032019', '', '', 0, '', '<div style=\"text-align: center;\"><br  /> &nbsp;</div>  <div style=\"text-align: justify;\"><span style=\"font-size:16px;\">Quý khách hàng vui lòng kiểm tra số thứ tự của mình và <strong>đợi tin nhắn hẹn thời gian tiêm của cơ sở tiêm chủng</strong>.</span></div>  <div style=\"text-align: justify;\"><span style=\"font-size:16px;\">Những khách hàng có số thứ tự được <strong><span style=\"color:rgb(231, 76, 60);\">bôi vàng</span></strong><span style=\"color:null;\">,<strong><span style=\"color:rgb(231, 76, 60);\"> </span></strong>vu</span>i lòng liên hệ cơ sở tiêm chủng để cập nhật thông tin.<br  /> Khi đến tiêm chủng,&nbsp;quý khách vui lòng<span style=\"color:rgb(231, 76, 60);\"><strong> mang theo CMND</strong></span> và <span style=\"color:rgb(231, 76, 60);\"><strong>cung cấp đúng, đầy đủ số điện thoại </strong></span>đã đăng ký để cơ sở tiện việc kiểm tra, đối chiếu.</span></div>  <div style=\"text-align: justify;\"><br  /> <iframe frameborder=\"0\" src=\"https://docs.google.com/spreadsheets/d/1sCY9rG0Nn-nUcUo-I_9nGot-JNLkkROD9tIzn405GBs/edit?usp=sharing\" style=\"height: 700px; width: 100%;\"></iframe></div>', 'danh sách,đăng ký', 0, '4', '', 0, 2, 2, 1554885116, 1555051111, 1, 6088, 0), 
(7, 'Khách hàng có nhu cầu tiêm chủng Vắc xin 6 trong 1 cần lưu ý', 'Khach-hang-co-nhu-cau-tiem-chung-Vac-xin-6-trong-1-can-luu-y-8', 'vac-xin-650.jpg', '', 0, 'Vắc xin 6 trong 1 hiện nay đang trong tình trạng khan hiếm, không đủ đáp ứng nhu cầu tiêm chủng của khách hàng. Để đảm bảo phòng bệnh sớm và đầy đủ cho trẻ, khách hàng có thể liên hệ các Trạm Y tế xã/phường trên địa bàn thành phố (mỗi tháng có 2 đợt tiêm) để chủng ngừa vắc xin 5 trong 1    (COMBE FIVE).', '<p style=\"text-align: justify;\"><span style=\"font-size:16px;\">- Vắc xin <span style=\"color:rgb(231, 76, 60);\"><strong>6 trong 1</strong></span> hiện nay đang trong tình trạng <span style=\"color:rgb(231, 76, 60);\"><strong>khan hiếm</strong></span>, không đủ đáp ứng nhu cầu tiêm chủng của khách hàng. Để đảm bảo phòng bệnh sớm và đầy đủ cho trẻ, khách hàng <strong>có thể liên hệ</strong> các Trạm Y tế xã/phường trên địa bàn thành phố (mỗi tháng có 2 đợt tiêm) để chủng ngừa vắc xin <span style=\"color:rgb(231, 76, 60);\"><strong>5 trong 1&nbsp;</strong></span>(COMBE FIVE).<br  /> <br  /> - Vắc xin Combe Five trong chương trình Tiêm chủng mở rộng giúp phòng ngừa 5 bệnh: Bạch hầu, Ho gà, Uốn ván, Viêm gan B và Viêm màng não, viêm phổi do Hib. Khi tiêm vắc xin Combe Five trẻ sẽ được uống cùng với 2 giọt vắc xin Bại liệt đảm bảo phòng ngừa đủ 6 bệnh như vắc xin 6 trong 1.<br  /> <br  /> - <span style=\"color:rgb(231, 76, 60);\"><strong>Điểm khác biệt</strong></span> lớn nhất giữa vắc xin <span style=\"color:rgb(231, 76, 60);\"><strong>5 trong 1</strong></span> (Combe Five) và vắc xin <span style=\"color:rgb(231, 76, 60);\"><strong>6 trong 1</strong></span>: Thành phần ho gà trong vắc xin 5 trong 1 là toàn tế bào nên đáp ứng miễn dịch mạnh hơn, tốt hơn và tất nhiên tác dụng phụ thông thường cũng nhiều hơn. Còn ho gà trong vắc xin 6 trong 1 là vô bào, đã được tinh chế nên tỷ lệ tác dụng phụ thông thường ít hơn. Tuy nhiên, tỷ lệ phản ứng nặng như sốc, co giật, tím tái... của hai loại vắc xin này là tương đương nhau. Đà Nẵng bắt đầu triển khai tiêm vắc xin Combe Five từ đầu năm 2019 đến nay (đến cuối tháng 3/2019 đã tiêm cho hơn 3200 lượt trẻ) ghi nhận khoảng <strong>11%</strong> trong số các trẻ được tiêm có phản ứng nhẹ, thông thường như sốt, sưng chỗ tiêm, quấy khóc…<strong>Chưa ghi nhận</strong> ca phản ứng nặng nào.<br  /> <br  /> - Trẻ <strong>đã tiêm</strong> mũi vắc xin <strong>6 trong 1</strong> trước đó <strong>có thể sử dụng</strong> vắc xin <strong>5 trong 1</strong> (Combe Five) <strong>và uống vắc xin bại liệt để thay thế</strong>, vẫn tính là mũi tiếp theo (không tiêm lại từ đầu) và <strong>đảm bảo hiệu quả</strong> phòng bệnh.<br  /> <br  /> - Vắc xin 5 trong 1 hay 6 trong 1 tiêm chủng cho trẻ từ 2 tháng tuổi, gồm 3 mũi cơ bản, mỗi mũi cách nhau ít nhất 1 tháng (3 mũi cơ bản này cần hoàn thành sớm và trước 12 tháng tuổi) và 1 mũi nhắc lại trước 24 tháng tuổi. </span></p>', '6 trong 1, 5 trong 1, vắc xin,', 0, '4', '', 0, 1, 2, 1547829042, 1554281192, 1, 27517, 1);
